        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: tLENGTH_MEASURE.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]PITCH for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( PITCH: p0 )
      }
    }
  }
}
